import React, { useState } from 'react';
import FormInput from '../components/FormInput';
import Button from '../components/Button';
import Card from '../components/Card';
import { serviceAPI, apiUtils } from '../services/api';

const ResellValue = () => {
  const [formData, setFormData] = useState({
    bikeModel: '',
    year: '',
    kmRun: '',
    condition: '',
    location: '',
    hasAccidents: false,
    modifications: false
  });
  const [valuation, setValuation] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const bikeModels = [
    { value: 'honda-cb-shine', label: 'Honda CB Shine', originalPrice: 75000 },
    { value: 'hero-splendor', label: 'Hero Splendor Plus', originalPrice: 65000 },
    { value: 'bajaj-pulsar-150', label: 'Bajaj Pulsar 150', originalPrice: 95000 },
    { value: 'tvs-apache', label: 'TVS Apache RTR 160', originalPrice: 110000 },
    { value: 'yamaha-fz', label: 'Yamaha FZ-S', originalPrice: 105000 },
    { value: 're-classic', label: 'Royal Enfield Classic 350', originalPrice: 185000 },
    { value: 'ktm-duke', label: 'KTM Duke 200', originalPrice: 175000 },
    { value: 'suzuki-gixxer', label: 'Suzuki Gixxer', originalPrice: 115000 }
  ];

  const years = Array.from({ length: 15 }, (_, i) => 2024 - i);

  const conditions = [
    { value: 'excellent', label: 'Excellent - Like new condition' },
    { value: 'good', label: 'Good - Minor wear and tear' },
    { value: 'fair', label: 'Fair - Visible wear, needs minor repairs' },
    { value: 'poor', label: 'Poor - Significant wear, needs major repairs' }
  ];

  const locations = [
    'Mumbai', 'Delhi', 'Bangalore', 'Chennai', 'Kolkata', 'Hyderabad', 
    'Pune', 'Ahmedabad', 'Jaipur', 'Lucknow', 'Other'
  ];

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData({
      ...formData,
      [name]: type === 'checkbox' ? checked : value
    });
  };

  const calculateResellValue = () => {
    setLoading(true);

    setTimeout(() => {
      const selectedBike = bikeModels.find(bike => bike.value === formData.bikeModel);

      if (!selectedBike) {
        setLoading(false);
        return;
      }

      let baseValue = selectedBike.originalPrice;
      const currentYear = 2024;
      const bikeAge = currentYear - parseInt(formData.year);

      // Depreciation based on age (15% first year, 10% subsequent years)
      let depreciationRate = 0.15; // First year
      if (bikeAge > 1) {
        depreciationRate = 0.15 + (bikeAge - 1) * 0.10;
      }
      depreciationRate = Math.min(depreciationRate, 0.80); // Max 80% depreciation

      baseValue *= (1 - depreciationRate);

      // Condition adjustment
      const conditionMultiplier = {
        'excellent': 1.0,
        'good': 0.85,
        'fair': 0.70,
        'poor': 0.50
      };
      baseValue *= conditionMultiplier[formData.condition] || 0.85;

      // KM run adjustment
      const kmRun = parseInt(formData.kmRun);
      if (kmRun > 50000) {
        baseValue *= 0.80;
      } else if (kmRun > 30000) {
        baseValue *= 0.90;
      } else if (kmRun > 15000) {
        baseValue *= 0.95;
      }

      // Accident history
      if (formData.hasAccidents) {
        baseValue *= 0.75;
      }

      // Modifications
      if (formData.modifications) {
        baseValue *= 0.90; // Modifications usually decrease resale value
      }

      // Location adjustment (metro cities have higher resale value)
      const metroCities = ['Mumbai', 'Delhi', 'Bangalore', 'Chennai', 'Kolkata', 'Hyderabad'];
      if (metroCities.includes(formData.location)) {
        baseValue *= 1.05;
      }

      const estimatedValue = Math.round(baseValue);
      const minValue = Math.round(estimatedValue * 0.85);
      const maxValue = Math.round(estimatedValue * 1.15);

      setValuation({
        bikeModel: selectedBike.label,
        originalPrice: selectedBike.originalPrice,
        estimatedValue,
        minValue,
        maxValue,
        depreciationPercent: Math.round(depreciationRate * 100),
        bikeAge,
        marketDemand: getMarketDemand(formData.bikeModel),
        tips: getSellingTips(formData.condition)
      });

      setLoading(false);
    }, 1500);
  };

  const getMarketDemand = (bikeModel) => {
    const demandMap = {
      'honda-cb-shine': 'High',
      'hero-splendor': 'High',
      'bajaj-pulsar-150': 'Medium',
      'tvs-apache': 'Medium',
      'yamaha-fz': 'Medium',
      're-classic': 'High',
      'ktm-duke': 'Medium',
      'suzuki-gixxer': 'Medium'
    };
    return demandMap[bikeModel] || 'Medium';
  };

  const getSellingTips = (condition) => {
    const tips = {
      'excellent': [
        'Highlight the excellent condition in your listing',
        'Include detailed photos from all angles',
        'Provide complete service history'
      ],
      'good': [
        'Clean the bike thoroughly before showing',
        'Fix minor issues to improve value',
        'Be transparent about any wear and tear'
      ],
      'fair': [
        'Consider basic repairs to increase value',
        'Price competitively for quick sale',
        'Highlight any recent maintenance'
      ],
      'poor': [
        'Be honest about the condition',
        'Consider selling to dealers or scrap buyers',
        'Price significantly below market rate'
      ]
    };
    return tips[condition] || tips['good'];
  };

  return (
    <div className="resell-value">
      <div className="container">
        <div className="page-header">
          <h1>Resell Value Calculator</h1>
          <p>Get an accurate estimate of your bike's current market value</p>
        </div>

        <div className="resell-content">
          <div className="resell-form-section">
            <Card className="resell-form-card">
              <h2>Bike Information</h2>
              <form className="resell-form">
                <FormInput
                  label="Bike Model"
                  type="select"
                  name="bikeModel"
                  value={formData.bikeModel}
                  onChange={handleChange}
                  options={bikeModels}
                  placeholder="Select your bike model"
                  required
                />

                <div className="form-row">
                  <FormInput
                    label="Year of Purchase"
                    type="select"
                    name="year"
                    value={formData.year}
                    onChange={handleChange}
                    options={years}
                    placeholder="Select year"
                    required
                  />
                  <FormInput
                    label="KM Run"
                    type="number"
                    name="kmRun"
                    value={formData.kmRun}
                    onChange={handleChange}
                    placeholder="Enter kilometers"
                    required
                  />
                </div>

                <FormInput
                  label="Overall Condition"
                  type="select"
                  name="condition"
                  value={formData.condition}
                  onChange={handleChange}
                  options={conditions}
                  placeholder="Select bike condition"
                  required
                />

                <FormInput
                  label="Location"
                  type="select"
                  name="location"
                  value={formData.location}
                  onChange={handleChange}
                  options={locations}
                  placeholder="Select your city"
                  required
                />

                <div className="checkbox-group">
                  <label className="checkbox-label">
                    <input
                      type="checkbox"
                      name="hasAccidents"
                      checked={formData.hasAccidents}
                      onChange={handleChange}
                    />
                    <span className="checkmark"></span>
                    Has accident history
                  </label>
                </div>

                <div className="checkbox-group">
                  <label className="checkbox-label">
                    <input
                      type="checkbox"
                      name="modifications"
                      checked={formData.modifications}
                      onChange={handleChange}
                    />
                    <span className="checkmark"></span>
                    Has modifications/aftermarket parts
                  </label>
                </div>

                <Button
                  type="button"
                  variant="primary"
                  size="large"
                  onClick={calculateResellValue}
                  disabled={!formData.bikeModel || !formData.year || !formData.kmRun || !formData.condition || loading}
                  className="calculate-btn"
                >
                  {loading ? 'Calculating...' : 'Calculate Resell Value'}
                </Button>
              </form>
            </Card>
          </div>

          <div className="resell-result-section">
            {valuation ? (
              <Card className="valuation-result-card">
                <h2>Valuation Report</h2>
                <div className="valuation-details">
                  <div className="valuation-header">
                    <h3>{valuation.bikeModel}</h3>
                    <p>{formData.year} Model • {formData.kmRun} KM</p>
                  </div>

                  <div className="value-range">
                    <div className="value-item">
                      <span className="value-label">Minimum Value</span>
                      <span className="value-amount min">₹{valuation.minValue.toLocaleString()}</span>
                    </div>
                    <div className="value-item main-value">
                      <span className="value-label">Estimated Value</span>
                      <span className="value-amount">₹{valuation.estimatedValue.toLocaleString()}</span>
                    </div>
                    <div className="value-item">
                      <span className="value-label">Maximum Value</span>
                      <span className="value-amount max">₹{valuation.maxValue.toLocaleString()}</span>
                    </div>
                  </div>

                  <div className="valuation-info">
                    <div className="info-row">
                      <span>Original Price:</span>
                      <span>₹{valuation.originalPrice.toLocaleString()}</span>
                    </div>
                    <div className="info-row">
                      <span>Depreciation:</span>
                      <span>{valuation.depreciationPercent}%</span>
                    </div>
                    <div className="info-row">
                      <span>Bike Age:</span>
                      <span>{valuation.bikeAge} years</span>
                    </div>
                    <div className="info-row">
                      <span>Market Demand:</span>
                      <span className={`demand-${valuation.marketDemand.toLowerCase()}`}>
                        {valuation.marketDemand}
                      </span>
                    </div>
                  </div>

                  <div className="selling-tips">
                    <h4>Selling Tips</h4>
                    <ul>
                      {valuation.tips.map((tip, index) => (
                        <li key={index}>{tip}</li>
                      ))}
                    </ul>
                  </div>

                  <Button variant="primary" size="large" className="sell-now-btn">
                    List for Sale
                  </Button>
                </div>
              </Card>
            ) : (
              <Card className="valuation-placeholder">
                <div className="placeholder-content">
                  <div className="placeholder-icon">📊</div>
                  <h3>Resell Value</h3>
                  <p>Fill in your bike details to get an accurate market valuation</p>
                </div>
              </Card>
            )}
          </div>
        </div>

        {/* Market Trends */}
        <section className="market-trends">
          <h2>Market Trends</h2>
          <div className="trends-grid">
            <Card className="trend-card">
              <h3>Commuter Bikes</h3>
              <div className="trend-indicator positive">↗️ +5%</div>
              <p>High demand for fuel-efficient bikes</p>
            </Card>
            <Card className="trend-card">
              <h3>Sports Bikes</h3>
              <div className="trend-indicator neutral">→ 0%</div>
              <p>Stable market with steady demand</p>
            </Card>
            <Card className="trend-card">
              <h3>Cruiser Bikes</h3>
              <div className="trend-indicator positive">↗️ +8%</div>
              <p>Growing popularity among enthusiasts</p>
            </Card>
          </div>
        </section>
      </div>
    </div>
  );
};

export default ResellValue;
